mapper.select:
SELECT a.id, a.project_id AS "projectId", a.repair_no AS "repairNo", a.type, a.location, a.description, a.before_attachments AS "beforeAttachments", a.contact, a.contact_number AS "contactNumber", a.status, a.repair_at AS "repairAt", a.after_attachments AS "afterAttachments", a.repair_result AS "repairResult", a.repair_member_id AS "repairMemberId", a.expected_visit_at AS "expectedVisitAt", a.complete_at AS "completeAt", a.created_by AS "createdBy", a.updated_by AS "updatedBy", a.created_at AS "createdAt", a.updated_at AS "updatedAt", p.code AS "projectCode", p.name AS "projectName", creator.name AS "createdByName", updater.name AS "updatedByName", COALESCE(member_user.id, legacy_member_user.id) AS "repairMemberUserId", COALESCE(member_user.name, legacy_member_user.name) AS "repairMemberName", COALESCE(member_user.avatar, legacy_member_user.avatar) AS "repairMemberAvatar", COALESCE(member_user.phone, legacy_member_user.phone) AS "repairMemberPhone", repair_member.role_code AS "repairMemberRoleCode", CASE repair_member.role_code WHEN 1 THEN '设计师' WHEN 2 THEN '设计助理' WHEN 3 THEN '土建项目经理' WHEN 4 THEN '精装项目经理' WHEN 5 THEN '施工员' WHEN 6 THEN '质检员' WHEN 7 THEN '成控人员' WHEN 8 THEN '财务人员' WHEN 9 THEN '老板/管理层' WHEN 10 THEN '业主' WHEN 11 THEN '业主家属' ELSE '' END AS "repairMemberRoleName", CASE a.status WHEN 1 THEN '待派单' WHEN 2 THEN '处理中' WHEN 3 THEN '待验收' WHEN 4 THEN '已完成' WHEN 5 THEN '已取消' ELSE '' END AS "statusText" FROM repair a LEFT JOIN project p ON p.id = a.project_id LEFT JOIN sys_account creator ON creator.id = a.created_by LEFT JOIN sys_account updater ON updater.id = a.updated_by LEFT JOIN project_member repair_member ON repair_member.id = a.repair_member_id LEFT JOIN sys_account member_user ON member_user.id = repair_member.user_id LEFT JOIN sys_account legacy_member_user ON legacy_member_user.id = a.repair_member_id
AND a.project_id = #{params.projectId}
AND p.name LIKE CONCAT('%', #{params.projectName}, '%') AND p.name LIKE '%' || #{params.projectName} || '%'
AND (a.repair_no LIKE CONCAT('%', #{params.keyword}, '%') OR a.description LIKE CONCAT('%', #{params.keyword}, '%') OR a.type LIKE CONCAT('%', #{params.keyword}, '%')) AND (a.repair_no LIKE '%' || #{params.keyword} || '%' OR a.description LIKE '%' || #{params.keyword} || '%' OR a.type LIKE '%' || #{params.keyword} || '%')
AND a.status = #{params.status} AND a.created_by = #{params.createdBy}
ORDER BY a.repair_at DESC, a.id DESC
